module RefModule(
    input [7:0] A,
    input [7:0] B,
    output reg [15:0] Y
);reg [15:0] final_sig;

integer i;

always @(*) begin
    final_sig = 16'b0;
    for (i = 0; i < 8; i = i + 1) begin
        if (A[i]) begin
            final_sig = final_sig + (B << i);
        end
    end
    Y = final_sig;
end

endmodule
